1	export type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: any[];
4	};
5	
6	export type ScenarioResult = {
7	  results: any[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE = 0.1;
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	};
18	
19	const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);
20	
21	const itemPremium = (item: any) =>
22	  BASE_PREMIUM[item.type] * (1 + FIRST_INSURANCE_SURCHARGE);
23	
24	const quote = (step: any) => {
25	  const total = step.items.reduce(
26	    (sum: number, item: any) => sum + itemPremium(item),
27	    PROCESSING_FEE,
28	  );
29	  return { premium: roundUp(total) };
30	};
31	
32	export const runScenario = (scenario: Scenario): ScenarioResult => {
33	  const results = scenario.steps.map((step) => {
34	    if (step.op === "quote") return quote(step);
35	    return {};
36	  });
37	  return { results };
38	};
39

